import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";
import { T, fonts, Spinner, PageHeader, PrimaryBtn, SVGIcon, Card } from "./designSystem";

const Freelancers = () => {
  const navigate = useNavigate();
  const [freelancers, setFreelancers]   = useState([]);
  const [loading,     setLoading]       = useState(true);
  const [sending,     setSending]       = useState(null);
  const [search,      setSearch]        = useState("");

  useEffect(() => {
    API.get("/users/freelancers")
      .then(r => setFreelancers(r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const handleMessage = async (f) => {
    setSending(f.id);
    try {
      await API.post("/messages", { receiver_id:f.id, content:`Hi ${f.name}! I'd like to connect with you.` });
    } catch {}
    setSending(null);
    navigate("/client/messages");
  };

  const filtered = freelancers.filter(f =>
    f.name?.toLowerCase().includes(search.toLowerCase()) ||
    f.email?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div style={{ minHeight:"100vh", background:T.pageBg, fontFamily:"'DM Sans',sans-serif" }}>
      <link href={fonts} rel="stylesheet"/>
      <div style={{ maxWidth:1100, margin:"0 auto", padding:"36px 28px" }}>

        <PageHeader
          eyebrow="Talent Pool"
          title="Browse Freelancers"
          subtitle="Connect with skilled freelancers for your projects"
        />

        {/* Search bar */}
        <div style={{ position:"relative", marginBottom:28, maxWidth:380 }}>
          <span style={{ position:"absolute", left:13, top:"50%", transform:"translateY(-50%)" }}>
            <SVGIcon d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" color={T.muted} size={16}/>
          </span>
          <input value={search} onChange={e=>setSearch(e.target.value)}
            placeholder="Search freelancers..."
            style={{ width:"100%", padding:"10px 14px 10px 38px", borderRadius:10,
              border:`1.5px solid ${T.border}`, fontSize:13, color:T.text, background:"#fff",
              outline:"none", fontFamily:"'DM Sans',sans-serif", boxSizing:"border-box" }}
            onFocus={e=>e.target.style.border=`1.5px solid ${T.accent}`}
            onBlur={e=>e.target.style.border=`1.5px solid ${T.border}`}/>
        </div>

        {loading ? <Card><Spinner/></Card> : filtered.length === 0 ? (
          <Card>
            <div style={{ padding:"60px 20px", textAlign:"center" }}>
              <div style={{ fontSize:52, marginBottom:12 }}>👥</div>
              <p style={{ color:T.muted }}>No freelancers found</p>
            </div>
          </Card>
        ) : (
          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))", gap:16 }}>
            {filtered.map(f => (
              <div key={f.id} style={{ background:T.card, borderRadius:16,
                border:`1px solid ${T.border}`, padding:"22px", boxShadow:"0 1px 3px rgba(0,0,0,0.05)",
                transition:"box-shadow .2s, transform .2s" }}
                onMouseEnter={e=>{e.currentTarget.style.boxShadow="0 6px 20px rgba(0,0,0,0.09)";e.currentTarget.style.transform="translateY(-2px)"}}
                onMouseLeave={e=>{e.currentTarget.style.boxShadow="0 1px 3px rgba(0,0,0,0.05)";e.currentTarget.style.transform="translateY(0)"}}>

                {/* Avatar + info */}
                <div style={{ display:"flex", alignItems:"center", gap:14, marginBottom:18 }}>
                  <div style={{ width:48, height:48, borderRadius:14,
                    background:`linear-gradient(135deg,${T.accent},${T.accent2})`,
                    color:"#fff", display:"flex", alignItems:"center", justifyContent:"center",
                    fontSize:20, fontWeight:800, fontFamily:"'Syne',sans-serif", flexShrink:0 }}>
                    {f.name?.charAt(0).toUpperCase()}
                  </div>
                  <div style={{ flex:1, minWidth:0 }}>
                    <h3 style={{ margin:0, fontSize:15, fontWeight:700, color:T.text,
                      fontFamily:"'Syne',sans-serif", whiteSpace:"nowrap", overflow:"hidden",
                      textOverflow:"ellipsis" }}>{f.name}</h3>
                    <p style={{ margin:"2px 0 4px", fontSize:12, color:T.muted,
                      whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>{f.email}</p>
                    <span style={{ padding:"2px 9px", background:`${T.accent}1A`, color:T.accent,
                      borderRadius:6, fontSize:10, fontWeight:700 }}>FREELANCER</span>
                  </div>
                </div>

                {/* Skills preview if available */}
                {f.skills && (
                  <div style={{ display:"flex", gap:5, flexWrap:"wrap", marginBottom:16 }}>
                    {f.skills.split(",").slice(0,3).map(s => (
                      <span key={s} style={{ padding:"2px 8px", background:"#F8FAFC",
                        border:`1px solid ${T.border}`, borderRadius:5, fontSize:10, color:"#475569" }}>
                        {s.trim()}
                      </span>
                    ))}
                  </div>
                )}

                {/* Buttons */}
                <div style={{ display:"flex", gap:8 }}>
                  <button onClick={() => handleMessage(f)} disabled={sending===f.id} style={{
                    flex:2, display:"flex", alignItems:"center", justifyContent:"center", gap:6,
                    background: sending===f.id ? T.muted : `linear-gradient(135deg,${T.accent},${T.accent2})`,
                    color:"#fff", border:"none", borderRadius:9, padding:"9px 0",
                    fontSize:12, fontWeight:700, cursor: sending===f.id ? "not-allowed" : "pointer",
                    fontFamily:"'DM Sans',sans-serif",
                  }}>
                    <SVGIcon d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" color="#fff" size={13}/>
                    {sending===f.id ? "Sending..." : "Message"}
                  </button>
                  <button onClick={() => alert(`Invitation sent to ${f.name}`)} style={{
                    flex:1, display:"flex", alignItems:"center", justifyContent:"center", gap:5,
                    background:`${T.accent}12`, color:T.accent, border:`1px solid ${T.accent}28`,
                    borderRadius:9, padding:"9px 0", fontSize:12, fontWeight:700,
                    cursor:"pointer", fontFamily:"'DM Sans',sans-serif",
                  }}>
                    <SVGIcon d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" color={T.accent} size={13}/>
                    Invite
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};
export default Freelancers;
